94	start(_ctx: StartupContext): void {
95	  const stacks = guild().apparatus<StacksApi>('stacks');
96	  writs = stacks.book<WritDoc>('clerk', 'writs');
97	  links = stacks.book<WritLinkDoc>('clerk', 'links');
98	},
